-- =============================================================================
-- Migración 00049 — Carga de deudas pendientes para socios de apellidos A-C (2026)
-- Cooperativa Primero de Mayo · SistemaCooperativa
-- -----------------------------------------------------------------------------
-- Inserta o actualiza 258 registros de deudas pendientes del Excel en Supabase.
-- =============================================================================

DO $$
DECLARE
    v_user_uuid uuid := '9cf2712a-3e6b-4634-84f0-eb40aa840f87'; -- ID administrador
BEGIN
    ON CONFLICT (puesto_id, concepto_id, periodo_anio, periodo_mes) 
    WHERE deleted_at IS NULL AND puesto_id IS NOT NULL 
    DO UPDATE SET 
        monto = EXCLUDED.monto,
        observacion = EXCLUDED.observacion,
        updated_at = now()
    WHERE montos_por_cobrar.estado = 'Pendiente';

    RAISE NOTICE 'Se han migrado/actualizado con éxito las deudas pendientes de socios A-C.';
END $$;